<?php
namespace App\Models;
class Assessment extends Model { private array $weights=['Cumplimiento Laboral'=>0.30,'Cumplimiento Previsional'=>0.25,'Seguridad y Salud Ocupacional'=>0.25,'Control Documental'=>0.10,'Gestión de Contratistas'=>0.10];
 public function questions(){return $this->db->query('SELECT * FROM assessment_questions WHERE status=1 ORDER BY sort_order')->fetchAll();}
 public function store($data){$this->db->beginTransaction(); try{$calc=$this->calculate($data['answers'],$data['industry']); $s=$this->db->prepare('INSERT INTO clients(company_name,company_rut,contact_name,position,email,phone,workers_count,industry,city,risk_score,risk_level,risk_status,recommended_action,source,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),NOW())');$s->execute([$data['company_name'],$data['company_rut'],$data['contact_name'],$data['position']??'',$data['email'],$data['phone']??'',(int)($data['workers_count']??0),$data['industry'],$data['city']??'', $calc['final_score'],$calc['risk_level'],'Nuevo',$calc['recommendation'],'Autoevaluación web']);$client=(int)$this->db->lastInsertId(); $qs=$this->questions(); foreach($qs as $q){$val=(int)($data['answers'][$q['id']]??0); $label=$val===10?'Sí':($val===5?'Parcial':'No'); $a=$this->db->prepare('INSERT INTO assessment_answers(client_id,question_id,answer_value,answer_label,module_name,created_at) VALUES(?,?,?,?,?,NOW())');$a->execute([$client,$q['id'],$val,$label,$q['module_name']]);} $r=$this->db->prepare('INSERT INTO assessment_results(client_id,labor_score,pension_score,safety_score,document_score,contractor_score,final_score,risk_level,recommendation,created_at) VALUES(?,?,?,?,?,?,?,?,?,NOW())');$r->execute([$client,$calc['modules']['Cumplimiento Laboral'],$calc['modules']['Cumplimiento Previsional'],$calc['modules']['Seguridad y Salud Ocupacional'],$calc['modules']['Control Documental'],$calc['modules']['Gestión de Contratistas'],$calc['final_score'],$calc['risk_level'],$calc['recommendation']]); $this->db->commit(); return ['client_id'=>$client]+$calc;}catch(\Throwable $e){$this->db->rollBack(); throw $e;}}
 public function calculate($answers,$industry=''){ $modules=[]; foreach($this->questions() as $q){$modules[$q['module_name']][]=(int)($answers[$q['id']]??0);} $scores=[];$final=0; foreach($this->weights as $m=>$w){$sum=array_sum($modules[$m]??[]);$max=max(1,count($modules[$m]??[])*10);$pct=($sum/$max)*100;$scores[$m]=round($pct,2);$final += $pct*$w;} $final=round($final,1); $level=$final>=85?'Riesgo bajo':($final>=60?'Riesgo medio':'Riesgo alto'); $rec=['Riesgo bajo'=>'Tu empresa presenta un adecuado nivel de cumplimiento y control. Se recomienda mantener los controles actuales y avanzar hacia procesos de mejora continua. Puedes conocer los beneficios del Sello Crecer.','Riesgo medio'=>'Se identifican oportunidades de mejora que podrían transformarse en incumplimientos futuros. Se recomienda fortalecer los procesos de control y cumplimiento.','Riesgo alto'=>'Se detectan brechas relevantes que podrían generar riesgos laborales, previsionales o documentales. Se recomienda implementar un plan de regularización y apoyo especializado.'][$level]; if(mb_strtolower($industry)==='minería') $rec.=' Conoce nuestra línea especializada Crecer Acredita Minería para empresas que prestan servicios a compañías mineras y requieren altos estándares de acreditación y control documental.'; return ['modules'=>$scores,'final_score'=>$final,'risk_level'=>$level,'recommendation'=>$rec];}
}
